from math import prod
from sympy import factorint
from sympy.ntheory.factor_ import digits
def A181861(n):
    def s(n,p): return sum(digits(n,p)[1:])
    return prod(p**min(e<<1,((n-(n&-2))+(s(n>>1,p)<<1)-s(n,p))//(p-1)) for p,e, in factorint(n).items()) if n else 1 # _Chai Wah Wu_, May 05 2026

